import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        char[] buffer = new char[10];

        // Copy user input into buffer with proper boundary checking
        int lengthToCopy = Math.min(userInput.length(), buffer.length);
        userInput.getChars(0, lengthToCopy, buffer, 0);

        System.out.println("User input copied securely into buffer.");
    }
}

